import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface GasPriceData {
  location: string;
  averagePrice: number;
  cheapestNearby: {
    station: string;
    price: number;
    distance: string;
  };
  priceTrend: number[];
}

export default function Widget() {
  const data = response.data as GasPriceData;
  const meta = response.meta;
  const isPriceDecreasing = data.priceTrend[data.priceTrend.length - 1] < data.priceTrend[0];

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 350,
        maxWidth: 450,
        bgcolor: meta.theme === 'dark' ? '#1E1E1E' : '#FFFFFF',
        color: meta.theme === 'dark' ? '#FFFFFF' : '#000000',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {data.location}
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ my: 0.5 }}>
              ${data.averagePrice.toFixed(2)}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Average Price
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Cheapest Nearby
            </Typography>
            <Stack direction="row" spacing={1} alignItems="center">
              <Typography variant="body2" fontWeight={500}>
                {data.cheapestNearby.station}
              </Typography>
              <Chip
                label={`$${data.cheapestNearby.price.toFixed(2)}`}
                sx={{
                  bgcolor: meta.primaryColor,
                  color: '#FFFFFF',
                  fontWeight: 500,
                }}
              />
              <Typography variant="body2" color="text.secondary">
                ({data.cheapestNearby.distance})
              </Typography>
            </Stack>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: data.priceTrend,
                color: isPriceDecreasing ? '#EF4444' : '#10B981',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: data.priceTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 1.5,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
